/**
 * Economy Creator/Origin Page — Attribution for strategy sources.
 * RESEARCH ONLY.
 */
import { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { api } from '../utils/api';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import usePageTitle from '../hooks/usePageTitle';
import { SkeletonTablePage } from '../components/SkeletonUI';
import s from './EconomyCreatorPage.module.css';

const T = { bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover, border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary, green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue, amber: tokens.color.amber, purple: tokens.color.purple, mono: tokens.font.mono };

export default function EconomyCreatorPage() {
  const { creatorId } = useParams();
  const nav = useNavigate();
  usePageTitle(`Creator: ${creatorId}`);
  const [creator, setCreator] = useState(null);
  const [strategies, setStrategies] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    (async () => {
      const [c, st] = await Promise.all([
        api(`/api/economy/creator/${creatorId}`),
        api(`/api/economy/strategies?limit=50`),
      ]);
      if (c) setCreator(c);
      if (st) setStrategies((st.strategies || []).filter(s => (s.creator_id || s.origin_type || '') === creatorId));
      setLoading(false);
    })();
  }, [creatorId]);

  if (loading) return <SkeletonTablePage title="Creator Profile" metricCount={3} cols={4} rows={5} />;
  if (!creator) return <div className={s.errorMsg}>Creator not found.</div>;

  return (
    <div className={s.container}>
      <button onClick={() => nav('/economy')} className={s.backBtn}>← Economy</button>

      <GlassPanel className={s.headerPanel}>
        <h1 className={s.creatorName}>{creator.display_name}</h1>
        <div className={s.creatorMeta}>{creator.creator_type} · {creator.description || ''}</div>
      </GlassPanel>

      <div className={s.metricsGrid}>
        {[
          { l: 'Published', v: creator.published_count || 0, c: T.blue },
          { l: 'Featured', v: creator.featured_count || 0, c: T.amber },
          { l: 'Avg Alpha', v: (creator.avg_alpha || 0).toFixed(3), c: T.green },
          { l: 'Avg Rep', v: (creator.avg_reputation || 0).toFixed(3), c: T.purple },
          { l: 'Followers', v: creator.followers_total || 0, c: T.text },
        ].map(m => (
          <GlassPanel key={m.l}>
            <div className={s.metricCell}>
              <div className={s.metricValue} style={{ color: m.c }}>{m.v}</div>
              <div className={s.metricLabel}>{m.l}</div>
            </div>
          </GlassPanel>
        ))}
      </div>

      <GlassPanel>
        <h3 className={s.sectionTitle}>PUBLISHED STRATEGIES</h3>
        {strategies.length === 0 ? (
          <div className={s.emptyMsg}>No strategies from this origin</div>
        ) : (
          <table className={s.table}>
            <thead><tr className={s.tableHeadRow}>
              {['Strategy', 'Alpha', 'Rep', 'Sharpe', 'PF', 'State'].map(h => (
                <th key={h} className={s.tableHeadCell}>{h}</th>
              ))}
            </tr></thead>
            <tbody>
              {strategies.map(st => (
                <tr key={st.strategy_version_id || st.strategy_root_id}
                  className={s.tableRow}
                  style={{ borderBottom: `1px solid ${T.border}22` }}
                  onClick={() => nav(`/economy/strategy/${st.strategy_version_id || st.strategy_root_id}`)}>
                  <td className={s.cellTitle}>{st.title || st.strategy_root_id}</td>
                  <td className={s.tableCell} style={{ color: st.alpha_score >= 0.7 ? T.green : T.text }}>{(st.alpha_score || 0).toFixed(3)}</td>
                  <td className={s.tableCell}>{(st.reputation_score || 0).toFixed(2)}</td>
                  <td className={s.tableCell}>{(st.sharpe || 0).toFixed(2)}</td>
                  <td className={s.tableCell}>{(st.profit_factor || 0).toFixed(2)}</td>
                  <td className={s.tableCell} style={{ color: st.publish_state === 'featured' ? T.amber : T.textSec }}>{st.publish_state}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </GlassPanel>
    </div>
  );
}
